diff --git a/test/validate-options.test.js b/test/validate-options.test.js
new file mode 100644
index 0000000..25eeffc
--- /dev/null
+++ b/test/validate-options.test.js
@@ -0,0 +1,117 @@
+/* eslint-disable global-require */
+import path from 'path';
+
+import { getCompiler, compile } from './helpers/index';
+
+describe('validate options', () => {
+  const tests = {
+    config: {
+      success: [
+        { path: 'test/fixtures/config/postcss.config.js' },
+        {
+          path: 'test/fixtures/config/postcss.config.js',
+          ctx: { plugin: true },
+        },
+      ],
+      failure: ['true', true, false, 'test', [], { foo: 'bar' }],
+    },
+    exec: {
+      success: [false],
+      failure: [1, 'test', /test/, [], {}, { foo: 'bar' }],
+    },
+    parser: {
+      success: ['sugarss', require('sugarss')],
+      failure: [1, true, false, []],
+    },
+    syntax: {
+      success: ['sugarss', require('sugarss')],
+      failure: [1, true, false, []],
+    },
+    stringifier: {
+      success: ['sugarss', require('sugarss')],
+      failure: [1, true, false, []],
+    },
+    sourceMap: {
+      success: ['source-map', true],
+      failure: [1, /test/, [], {}],
+    },
+    plugins: {
+      success: [
+        [require('./fixtures/config/plugin')()],
+        require('./fixtures/config/plugin'),
+        () => [require('./fixtures/config/plugin')()],
+      ],
+      failure: [1, true, false, /test/],
+    },
+  };
+
+  function stringifyValue(value) {
+    if (
+      Array.isArray(value) ||
+      (value && typeof value === 'object' && value.constructor === Object)
+    ) {
+      return JSON.stringify(value);
+    }
+
+    return value;
+  }
+
+  async function createTestCase(key, value, type) {
+    it(`should ${
+      type === 'success' ? 'successfully validate' : 'throw an error on'
+    } the "${key}" option with "${stringifyValue(value)}" value`, async () => {
+      let compiler;
+
+      if (key === 'parser' || key === 'syntax') {
+        compiler = getCompiler(
+          './sss/index.js',
+          {},
+          {
+            module: {
+              rules: [
+                {
+                  test: /\.sss$/i,
+                  use: [
+                    {
+                      loader: path.resolve(__dirname, '../src'),
+                      options: { [key]: value },
+                    },
+                  ],
+                },
+              ],
+            },
+          }
+        );
+      } else {
+        compiler = getCompiler('./css/index.js', { [key]: value });
+      }
+
+      let stats;
+
+      try {
+        stats = await compile(compiler);
+      } finally {
+        if (type === 'success') {
+          expect(stats.hasErrors()).toBe(false);
+        } else if (type === 'failure') {
+          const {
+            compilation: { errors },
+          } = stats;
+
+          expect(errors).toHaveLength(1);
+          expect(() => {
+            throw new Error(errors[0].error.message);
+          }).toThrowErrorMatchingSnapshot();
+        }
+      }
+    });
+  }
+
+  for (const [key, values] of Object.entries(tests)) {
+    for (const type of Object.keys(values)) {
+      for (const value of values[type]) {
+        createTestCase(key, value, type);
+      }
+    }
+  }
+});

