+        map: { inline: false, annotation: false },
+      },
+      config: false,
+    });
+    const stats = await compile(compiler);
+
+    const codeFromBundle = getCodeFromBundle('style.css', stats);
+    const notNormalizecodeFromBundle = getCodeFromBundle(
+      'style.css',
+      stats,
+      false
