diff --git a/test/stringifier.test.js b/test/stringifier.test.js
new file mode 100644
index 0000000..d860577
--- /dev/null
+++ b/test/stringifier.test.js
@@ -0,0 +1,71 @@
+import {
+  compile,
+  getCompiler,
+  getErrors,
+  getCodeFromBundle,
+  getWarnings,
+} from './helpers';
+
+describe('Options Stringifier', () => {
+  it('should work Stringifier - {String}', async () => {
+    const compiler = getCompiler('./css/index.js', {
+      postcssOptions: {
+        stringifier: 'sugarss',
+      },
+    });
+    const stats = await compile(compiler);
+
+    const codeFromBundle = getCodeFromBundle('style.css', stats);
+
+    expect(codeFromBundle.css).toMatchSnapshot('css');
+    expect(getWarnings(stats)).toMatchSnapshot('warnings');
+    expect(getErrors(stats)).toMatchSnapshot('errors');
+  });
+
+  it('should work Stringifier - {Object}', async () => {
+    const compiler = getCompiler('./css/index.js', {
+      postcssOptions: {
+        // eslint-disable-next-line global-require
+        stringifier: require('sugarss'),
+      },
+    });
+    const stats = await compile(compiler);
+
+    const codeFromBundle = getCodeFromBundle('style.css', stats);
+
+    expect(codeFromBundle.css).toMatchSnapshot('css');
+    expect(getWarnings(stats)).toMatchSnapshot('warnings');
+    expect(getErrors(stats)).toMatchSnapshot('errors');
+  });
+
+  it('should work Stringifier - {Function}', async () => {
+    // eslint-disable-next-line global-require
+    const Midas = require('midas');
+    const midas = new Midas();
+
+    const compiler = getCompiler('./css/index.js', {
+      postcssOptions: {
+        stringifier: midas.stringifier,
+      },
+    });
+    const stats = await compile(compiler);
+
+    const codeFromBundle = getCodeFromBundle('style.css', stats);
+
+    expect(codeFromBundle.css).toMatchSnapshot('css');
+    expect(getWarnings(stats)).toMatchSnapshot('warnings');
+    expect(getErrors(stats)).toMatchSnapshot('errors');
+  });
+
+  it('should throw an error on "unresolved" stringifier', async () => {
+    const compiler = getCompiler('./css/index.js', {
+      postcssOptions: {
+        stringifier: 'unresolved',
+      },
+    });
+    const stats = await compile(compiler);
+
+    expect(getWarnings(stats)).toMatchSnapshot('warnings');
+    expect(getErrors(stats, true)).toMatchSnapshot('errors');
+  });
+});

